// Extract email data and prepare for AI
const emailData = $input.first().json;
const headers = emailData.headers || {};

// Get subject
const subject = emailData.subject || headers.subject || headers.Subject || "(no subject)";

// Get from
let from = emailData.from || headers.from || headers.From || "";
const emailMatch = from.match(/<([^>]+)>/);
if (emailMatch) from = emailMatch[1];
if (!from.trim()) from = "(unknown sender)";

// Get body - IMAP node uses textPlain/textHtml, NOT text/html
const textBody = emailData.textPlain || "";
const htmlBody = emailData.textHtml || "";
const fullBody = textBody || htmlBody.replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim();
const snippet = fullBody.substring(0, 3000);

return [{
  json: {
    chatInput: `Analyze this email and classify it.

EMAIL:
Subject: "${subject}"
From: "${from}"
Body:
${snippet}

CATEGORIES:
- URGENT: Requires immediate attention (security alerts, account issues, deadlines today)
- ACTION_REQUIRED: Needs response or action within days
- IMPORTANT: Worth reading but not time-critical
- NOTIFICATION: Automated updates (order confirmations, bills)
- SHIPPING: Package shipped notification
- MARKETING: Promotional content, ads, sales
- NEWSLETTER: Subscribed content, digests
- SPAM: Unsolicited promotional content, scams

RULES:
1. If email is MARKETING, NEWSLETTER, or SPAM, return: {"category": "SKIP", "reason": "brief reason"}
2. For all other categories, return: {"category": "CATEGORY_NAME", "summary": "one-line summary"}

Respond with ONLY valid JSON. No markdown. No explanation.`,
    subject: subject,
    from: from,
    snippet: snippet
  }
}];

// Parse AI response and format message
const input = $input.first();
const emailData = $("Prepare Email Data").first().json;
const aiResponse = input.json.output || input.json.response || input.json.text || JSON.stringify(input.json);

let content = aiResponse.toString().replace(/```json\s*/g, "").replace(/```\s*/g, "").trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  const jsonMatch = content.match(/\{[\s\S]*?\}/);
  if (jsonMatch) {
    try { parsed = JSON.parse(jsonMatch[0]); }
    catch (e2) { parsed = { category: "SKIP", reason: "Parse failed" }; }
  } else {
    parsed = { category: "SKIP", reason: "No JSON found" };
  }
}

const category = parsed.category || "SKIP";
const skipCategories = ["SKIP", "SPAM", "MARKETING", "NEWSLETTER"];
if (skipCategories.includes(category)) return [];

const emoji = category === "URGENT" ? "🚨" : category === "ACTION_REQUIRED" ? "⚠️" : category === "IMPORTANT" ? "📧" : category === "SHIPPING" ? "📦" : "📩";
const summary = (parsed.summary || "").trim();
const from = emailData.from;
const subject = emailData.subject;

let message = emoji + " **" + category + "**\n\n**From:** " + from + "\n**Subject:** " + subject;
if (summary) {
  message += "\n**Summary:** " + summary;
}

return [{ json: { message: message } }];
